  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// 用户表\nmodel User {\n  id        String   @id @default(uuid())\n  username  String   @unique\n  password  String\n  avatar    String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // 关联\n  applications   Application[]\n  knowledgeBases KnowledgeBase[]\n  skills         Skill[]\n  chatHistories  ChatHistory[]\n\n  @@map(\"users\")\n}\n\n// 应用表\nmodel Application {\n  id          String   @id @default(uuid())\n  name        String\n  description String?\n  icon        String?\n  status      String   @default(\"draft\") // draft, published, archived\n  shareLink   String?  @unique\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // 外键\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // 关联\n  workflows Workflow[]\n\n  @@map(\"applications\")\n}\n\n// 工作流配置表\nmodel Workflow {\n  id          String  @id @default(uuid())\n  name        String\n  description String?\n\n  // 节点和边配置 (JSON存储)\n  nodes String\n  edges String\n\n  // 变量定义\n  variables String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // 外键\n  applicationId String\n  application   Application @relation(fields: [applicationId], references: [id], onDelete: Cascade)\n\n  // 关联\n  executions WorkflowExecution[]\n\n  @@map(\"workflows\")\n}\n\n// 工作流执行记录表\nmodel WorkflowExecution {\n  id     String @id @default(uuid())\n  status String @default(\"pending\") // pending, running, success, failed, cancelled\n\n  // 输入参数\n  inputs String?\n\n  // 执行上下文 (节点输出结果)\n  context String?\n\n  // 执行日志\n  logs String?\n\n  // 错误信息\n  error String?\n\n  // 执行耗时(ms)\n  duration Int?\n\n  // Tokens 监控\n  promptTokens     Int?\n  completionTokens Int?\n\n  startedAt   DateTime  @default(now())\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n\n  // 外键\n  workflowId String\n  workflow   Workflow @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n\n  @@map(\"workflow_executions\")\n}\n\n// 知识库表\nmodel KnowledgeBase {\n  id          String  @id @default(uuid())\n  name        String\n  description String?\n\n  // 嵌入模型配置\n  embeddingModel String @default(\"text-embedding-v2\")\n\n  // 分块配置\n  chunkSize    Int @default(500)\n  chunkOverlap Int @default(50)\n\n  // 检索配置\n  topK                Int   @default(5)\n  similarityThreshold Float @default(0.7)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // 外键\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // 关联\n  documents Document[]\n\n  @@unique([name, userId])\n  @@map(\"knowledge_bases\")\n}\n\n// 文档表\nmodel Document {\n  id              String          @id @default(uuid())\n  name            String\n  content         String\n  mimeType        String          @default(\"text/markdown\")\n  size            Int\n  status          String          @default(\"completed\")\n  error           String?\n  metadata        String?\n  createdAt       DateTime        @default(now())\n  updatedAt       DateTime        @updatedAt\n  knowledgeBaseId String\n  knowledgeBase   KnowledgeBase   @relation(fields: [knowledgeBaseId], references: [id], onDelete: Cascade)\n  chunks          DocumentChunk[]\n\n  @@unique([name, knowledgeBaseId])\n  @@map(\"documents\")\n}\n\n// 文档分块表 (向量存储)\nmodel DocumentChunk {\n  id      String @id @default(uuid())\n  content String\n\n  // 向量数据 (以JSON数组存储)\n  embedding String?\n\n  // 分块位置\n  chunkIndex Int\n  startIndex Int\n  endIndex   Int\n\n  // 元数据\n  metadata String?\n\n  createdAt DateTime @default(now())\n\n  // 外键\n  documentId String\n  document   Document @relation(fields: [documentId], references: [id], onDelete: Cascade)\n\n  @@index([documentId])\n  @@map(\"document_chunks\")\n}\n\n// Skill工具表\nmodel Skill {\n  id          String  @id @default(uuid())\n  name        String\n  description String?\n\n  // 工具类型: builtin(内置), custom(自定义)\n  type String @default(\"custom\")\n\n  // 内置工具类型标识\n  builtinType String?\n\n  // 自定义工具配置\n  config String?\n\n  // 输入参数定义\n  inputSchema String?\n\n  // 输出格式定义\n  outputSchema String?\n\n  // 是否启用\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // 外键\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"skills\")\n}\n\n// 对话历史表\nmodel ChatHistory {\n  id String @id @default(uuid())\n\n  // 会话ID\n  sessionId String\n\n  // 消息角色\n  role String // user, assistant, system\n\n  // 消息内容\n  content String\n\n  // 引用的知识库文档\n  references String?\n\n  // 使用的工具\n  toolCalls String?\n\n  // 元数据\n  metadata String?\n\n  createdAt DateTime @default(now())\n\n  // 外键\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([sessionId])\n  @@index([userId])\n  @@map(\"chat_histories\")\n}\n",
